    61→bool _hasPrimaryContext(DeviceIndex device_index) {
    62→  TORCH_CHECK(device_index >= 0 && device_index < at::cuda::device_count(),
    63→              "hasPrimaryContext expects a valid device index, but got device_index=", device_index);
    64→  unsigned int ctx_flags = 0;
    65→  // In standalone tests of cuDevicePrimaryCtxGetState, I've seen the "active" argument end up with weird
    66→  // (garbage-looking nonzero) values when the context is not active, unless I initialize it to zero.
    67→  int ctx_is_active = 0;
    68→  AT_CUDA_DRIVER_CHECK(nvrtc().cuDevicePrimaryCtxGetState(device_index, &ctx_flags, &ctx_is_active));
    69→  return ctx_is_active == 1;
    70→}
