   377→std::string CUDAHooks::showConfig() const {
   378→  std::ostringstream oss;
   379→
   380→  int runtimeVersion = 0;
   381→  AT_CUDA_CHECK(cudaRuntimeGetVersion(&runtimeVersion));
   382→
   383→  auto printCudaStyleVersion = [&](size_t v) {
   384→#ifdef USE_ROCM
   385→    // HIP_VERSION value format was changed after ROCm v4.2 to include the patch number
   386→    if(v < 500) {
   387→      // If major=xx, minor=yy then format -> xxyy
   388→      oss << (v / 100) << "." << (v % 10);
   389→    }
   390→    else {
   391→      // If major=xx, minor=yy & patch=zzzzz then format -> xxyyzzzzz
   392→      oss << (v / 10000000) << "." << (v / 100000 % 100) << "." << (v % 100000);
   393→    }
   394→#else
   395→    oss << (v / 1000) << "." << (v / 10 % 100);
   396→    if (v % 10 != 0) {
   397→      oss << "." << (v % 10);
   398→    }
   399→#endif
   400→  };
   401→
   402→#if !defined(USE_ROCM)
   403→  oss << "  - CUDA Runtime ";
   404→#else
   405→  oss << "  - HIP Runtime ";
   406→#endif
   407→  printCudaStyleVersion(runtimeVersion);
   408→  oss << "\n";
   409→
   410→  // TODO: Make HIPIFY understand CUDART_VERSION macro
   411→#if !defined(USE_ROCM)
   412→  if (runtimeVersion != CUDART_VERSION) {
   413→    oss << "  - Built with CUDA Runtime ";
   414→    printCudaStyleVersion(CUDART_VERSION);
   415→    oss << "\n";
   416→  }
   417→  oss << "  - NVCC architecture flags: " << NVCC_FLAGS_EXTRA << "\n";
   418→#endif
   419→
   420→#if !defined(USE_ROCM)
   421→#if AT_CUDNN_ENABLED()
   422→
   423→
   424→  auto printCudnnStyleVersion = [&](size_t v) {
   425→    oss << (v / 1000) << "." << (v / 100 % 10);
   426→    if (v % 100 != 0) {
   427→      oss << "." << (v % 100);
   428→    }
   429→  };
   430→
   431→  size_t cudnnVersion = cudnnGetVersion();
   432→  oss << "  - CuDNN ";
   433→  printCudnnStyleVersion(cudnnVersion);
   434→  size_t cudnnCudartVersion = cudnnGetCudartVersion();
   435→  if (cudnnCudartVersion != CUDART_VERSION) {
   436→    oss << "  (built against CUDA ";
   437→    printCudaStyleVersion(cudnnCudartVersion);
   438→    oss << ")";
   439→  }
   440→  oss << "\n";
   441→  if (cudnnVersion != CUDNN_VERSION) {
   442→    oss << "    - Built with CuDNN ";
   443→    printCudnnStyleVersion(CUDNN_VERSION);
   444→    oss << "\n";
   445→  }
   446→#endif
   447→#else
   448→  // TODO: Check if miopen has the functions above and unify
   449→  oss << "  - MIOpen " << MIOPEN_VERSION_MAJOR << "." << MIOPEN_VERSION_MINOR << "." << MIOPEN_VERSION_PATCH << "\n";
   450→#endif
   451→
   452→#if AT_MAGMA_ENABLED()
   453→  oss << "  - Magma " << MAGMA_VERSION_MAJOR << "." << MAGMA_VERSION_MINOR << "." << MAGMA_VERSION_MICRO << "\n";
   454→#endif
   455→
   456→  return oss.str();
   457→}
