        dO_,
        softmaxstats,
        dQ,
        dK,
        dV,
        dropoutseed,
        dropoutoffset,
        handle);
  }

  std::unordered_map<int64_t, void*> variant_pack = {
      // inputs
      {Q, q.data_ptr()},
      {K, k.data_ptr()},
      {V, v.data_ptr()},
      {O, o.data_ptr()},
      {DO, dO_.data_ptr()},
      {LSE, softmaxstats.data_ptr()},
      // outputs
      {DQ, dQ.data_ptr()},
      {DK, dK.data_ptr()},
      {DV, dV.data_ptr()},
      {SCALE, &scaling_factor},
